#include<bits/stdc++.h>
using namespace std;
int a[1005];
int main(){
    long long n,r,ans=0,num=0;
    cin>>n>>r;
    a[1]=r%100+1;
    for(int i=2;i<=n;i++){
        r=(r*6807+2831)%201701;
        a[i]=r%100+1;
    }
    sort(a+1,a+1+n);
    for(int i=1;i<=n;i++){
        num+=a[i];
        ans+=num;
    }
    cout<<ans;
    return 0;
}
